// chemistryPyq.js
// Class 11 Chemistry - Previous Year Questions.
// Default-exports a { chapterName: questionCardHtml } map consumed by allPyq.js
// (getPyqHtml -> SUBJECT_PYQ.Chemistry[chapter]).
//
// Chapter-name keys MUST match PracticeScreen's PYQ_SUBJECTS (Chemistry) exactly.
//
// PASTEL TEMPLATE: cards carry their OWN scoped styles (class prefix `pq-`) so the
// pastel look renders over buildPyqDocument's black/white CSS. Math/chemistry
// notation is written as {tex}...{/tex} so the app's MathJax renders subscripts
// and superscripts properly (e.g. {tex}NO_2^+{/tex}, {tex}C_p - C_v = R{/tex}).
// "Report Error" is clickable: confirms visually and posts {type:'report_error', id}
// to React Native if you add a WebView onMessage handler.

// ── Shared pastel styles + report-button script (include once per chapter) ──
const PQ_PASTEL_HEAD = `
<style>
  .pq-wrap{ font-family:-apple-system,Roboto,"Segoe UI",sans-serif; }
  .pq-card{ background:#ffffff; border:1px solid #ECEEF3; border-radius:18px;
            padding:20px; margin-bottom:16px; box-shadow:0 6px 20px rgba(17,24,39,0.06); }
  .pq-top{ display:flex; justify-content:space-between; align-items:center; margin-bottom:14px; }
  .pq-q{ font-size:13px; font-weight:800; color:#0F172A; letter-spacing:0.3px; }
  .pq-year{ font-size:12px; font-weight:700; color:#14B8A6; background:#ECFDFA;
            padding:4px 12px; border-radius:999px; }
  .pq-question{ font-size:16px; line-height:1.65; color:#1E293B; margin:0 0 16px; }

  /* MCQ options */
  .pq-opt{ display:flex; gap:12px; align-items:flex-start; background:#F5F6FA;
           border:1px solid #EEF0F5; border-radius:12px; padding:13px 16px;
           margin-bottom:10px; font-size:15px; color:#334155; }
  .pq-letter{ font-weight:800; color:#475569; min-width:16px; }
  .pq-opt-correct{ background:#ECFBF2; border:1px solid #BBF7D0;
                   border-left:4px solid #34D399; flex-direction:column; align-items:stretch; }
  .pq-correct-row{ display:flex; gap:12px; }
  .pq-correct-letter{ color:#059669; }
  .pq-expl-label{ color:#059669; font-weight:700; font-size:13px; margin:10px 0 6px; }
  .pq-expl{ border-left:3px solid #A7F3D0; padding-left:12px; color:#475569;
            font-size:14px; line-height:1.6; }
  .pq-expl p{ margin:3px 0; }

  /* Subjective solution box (cream) */
  .pq-solution{ background:#FBF6EC; border:1px solid #F2E7D2; border-radius:14px;
                padding:16px 18px; margin-top:4px; }
  .pq-solution-title{ font-size:14px; font-weight:800; color:#1C1C1E; margin-bottom:10px; }
  .pq-solution-body{ color:#6B7280; font-size:15px; line-height:1.75; }
  .pq-solution-body p{ margin:4px 0; }

  .pq-foot{ display:flex; justify-content:flex-end; margin-top:12px; }
  .pq-report{ font-family:inherit; font-size:13px; font-weight:600; color:#64748B;
              background:#ffffff; border:1px solid #E2E8F0; border-radius:10px;
              padding:9px 16px; cursor:pointer; }
  .pq-report:active{ background:#F8FAFC; }
</style>
<script>
  function pqReport(btn){
    btn.innerText='\\u2713 Reported';
    btn.style.color='#047857';
    btn.style.borderColor='#6EE7B7';
    btn.style.background='#ECFDF5';
    btn.disabled=true;
    try{
      if(window.ReactNativeWebView){
        window.ReactNativeWebView.postMessage(
          JSON.stringify({ type:'report_error', id: btn.getAttribute('data-qid') })
        );
      }
    }catch(e){}
  }
</script>
`;


// ── Structure of Atom ───────────────────────────────────────────────────────
const CHEM_STRUCTURE_OF_ATOM = PQ_PASTEL_HEAD + `
<div class="pq-wrap">
  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q1</span><span class="pq-year">1988</span></div>
    <p class="pq-question">The uncertainty principle and the concept of wave nature of matter were proposed by ________ and ________ respectively.</p>
    <div class="pq-solution">
      <div class="pq-solution-title">Solution</div>
      <div class="pq-solution-body">
        <p>The uncertainty principle was proposed by <strong>Heisenberg</strong>.</p>
        <p>The concept of the wave nature of matter (matter waves) was proposed by <strong>de Broglie</strong>.</p>
      </div>
    </div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-soa-q1" onclick="pqReport(this)">Report Error</button></div>
  </div>
</div>
`;


// ── Classification of Elements and Periodicity in Properties ─────────────────
const CHEM_PERIODICITY = PQ_PASTEL_HEAD + `
<div class="pq-wrap">
  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q1</span><span class="pq-year">2014</span></div>
    <p class="pq-question">In which of the following orders of ionic radii is correctly represented?</p>
    <div class="pq-opt"><span class="pq-letter">A</span><span>{tex}H^- > H^+ > H{/tex}</span></div>
    <div class="pq-opt"><span class="pq-letter">B</span><span>{tex}Na^+ > F^- > O^{2-}{/tex}</span></div>
    <div class="pq-opt"><span class="pq-letter">C</span><span>{tex}F^- > O^{2-} > Na^+{/tex}</span></div>
    <div class="pq-opt pq-opt-correct">
      <div class="pq-correct-row"><span class="pq-letter pq-correct-letter">D</span><span>None of these</span></div>
      <div class="pq-expl-label">Explanation:</div>
      <div class="pq-expl">
        <p>For a cation, anion and neutral species of the same atom, the cation is smaller than the neutral atom due to higher effective nuclear charge, and the anion is larger than the neutral atom due to lower effective nuclear charge.</p>
        <p>Thus, the correct order of ionic radii is {tex}H^- > H > H^+{/tex}.</p>
      </div>
    </div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-period-q1" onclick="pqReport(this)">Report Error</button></div>
  </div>
</div>
`;


// ── Chemical Bonding and Molecular Structure ─────────────────────────────────
const CHEM_BONDING = PQ_PASTEL_HEAD + `
<div class="pq-wrap">
  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q1</span><span class="pq-year">2016</span></div>
    <p class="pq-question">The hybridizations of atomic orbitals of nitrogen in {tex}NO_2^+{/tex}, {tex}NO_3^-{/tex} and {tex}NH_4^+{/tex} respectively are:</p>
    <div class="pq-opt pq-opt-correct">
      <div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span>{tex}sp,\\ sp^2 \\text{ and } sp^3{/tex}</span></div>
      <div class="pq-expl-label">Explanation:</div>
      <div class="pq-expl"><p>The hybrid orbitals of nitrogen in {tex}NO_2^+{/tex}, {tex}NO_3^-{/tex} and {tex}NH_4^+{/tex} are {tex}sp{/tex}, {tex}sp^2{/tex} and {tex}sp^3{/tex} respectively.</p></div>
    </div>
    <div class="pq-opt"><span class="pq-letter">B</span><span>{tex}sp,\\ sp^3 \\text{ and } sp^2{/tex}</span></div>
    <div class="pq-opt"><span class="pq-letter">C</span><span>{tex}sp^2,\\ sp \\text{ and } sp^3{/tex}</span></div>
    <div class="pq-opt"><span class="pq-letter">D</span><span>{tex}sp^2,\\ sp^3 \\text{ and } sp{/tex}</span></div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-bond-q1" onclick="pqReport(this)">Report Error</button></div>
  </div>

  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q2</span><span class="pq-year">2015</span></div>
    <p class="pq-question">Which of the following options represents the correct bond order?</p>
    <div class="pq-opt"><span class="pq-letter">A</span><span>{tex}O_2^- > O_2 > O_2^+{/tex}</span></div>
    <div class="pq-opt pq-opt-correct">
      <div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span>{tex}O_2^- < O_2 < O_2^+{/tex}</span></div>
      <div class="pq-expl-label">Explanation:</div>
      <div class="pq-expl">
        <p>Bond order {tex}= \\tfrac{1}{2}(N_b - N_a){/tex}, where {tex}N_b{/tex} and {tex}N_a{/tex} are the numbers of bonding and antibonding electrons.</p>
        <p>Bond orders: {tex}O_2^- = 1.5{/tex}, {tex}O_2 = 2{/tex}, {tex}O_2^+ = 2.5{/tex}, so {tex}O_2^- < O_2 < O_2^+{/tex}.</p>
      </div>
    </div>
    <div class="pq-opt"><span class="pq-letter">C</span><span>{tex}O_2^- > O_2 < O_2^+{/tex}</span></div>
    <div class="pq-opt"><span class="pq-letter">D</span><span>{tex}O_2^- < O_2 > O_2^+{/tex}</span></div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-bond-q2" onclick="pqReport(this)">Report Error</button></div>
  </div>

  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q3</span><span class="pq-year">2011</span></div>
    <p class="pq-question">Which of the following has minimum bond length?</p>
    <div class="pq-opt"><span class="pq-letter">A</span><span>{tex}O_2{/tex}</span></div>
    <div class="pq-opt pq-opt-correct">
      <div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span>{tex}O_2^+{/tex}</span></div>
      <div class="pq-expl-label">Explanation:</div>
      <div class="pq-expl">
        <p>Bond orders: {tex}O_2^- = 1.5{/tex}, {tex}O_2^{2-} = 1{/tex}, {tex}O_2 = 2{/tex}, {tex}O_2^+ = 2.5{/tex}.</p>
        <p>Since bond length {tex}\\propto \\tfrac{1}{\\text{bond order}}{/tex}, the species with the maximum bond order has the minimum bond length. Therefore {tex}O_2^+{/tex} has the minimum bond length.</p>
      </div>
    </div>
    <div class="pq-opt"><span class="pq-letter">C</span><span>{tex}O_2^-{/tex}</span></div>
    <div class="pq-opt"><span class="pq-letter">D</span><span>{tex}O_2^{2-}{/tex}</span></div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-bond-q3" onclick="pqReport(this)">Report Error</button></div>
  </div>

  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q4</span><span class="pq-year">1985</span></div>
    <p class="pq-question">All molecules with polar bonds have dipole moment. (True / False)</p>
    <div class="pq-opt"><span class="pq-letter">A</span><span>True</span></div>
    <div class="pq-opt pq-opt-correct">
      <div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span>False</span></div>
      <div class="pq-expl-label">Explanation:</div>
      <div class="pq-expl"><p>Symmetrical molecules with polar bonds (e.g. {tex}CO_2{/tex}, {tex}CCl_4{/tex}) have zero net dipole moment because the individual bond dipoles cancel out.</p></div>
    </div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-bond-q4" onclick="pqReport(this)">Report Error</button></div>
  </div>

  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q5</span><span class="pq-year">1984</span></div>
    <p class="pq-question">The H-N-H bond angle in {tex}NH_3{/tex} is greater than the H-As-H bond angle in {tex}AsH_3{/tex}. (Explain / True)</p>
    <div class="pq-solution">
      <div class="pq-solution-title">Solution</div>
      <div class="pq-solution-body">
        <p>True. Nitrogen is more electronegative than arsenic, so in {tex}NH_3{/tex} the bonding electron pairs are held closer to the central N atom, increasing bond-pair&ndash;bond-pair repulsion and widening the bond angle.</p>
        <p>In {tex}AsH_3{/tex}, the larger, less electronegative As atom holds the bonding pairs farther away, reducing repulsion and giving a smaller bond angle. Hence the H-N-H angle ({tex}\\approx 107^\\circ{/tex}) is greater than the H-As-H angle ({tex}\\approx 92^\\circ{/tex}).</p>
      </div>
    </div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-bond-q5" onclick="pqReport(this)">Report Error</button></div>
  </div>
</div>
`;


// ── States of Matter - Gases and Liquids (FA ONLY) ──────────────────────────
const CHEM_STATES_OF_MATTER = PQ_PASTEL_HEAD + `
<div class="pq-wrap">
  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q1</span><span class="pq-year">1998</span></div>
    <p class="pq-question"><strong>Assertion (A):</strong> The value of van der Waals' constant 'a' is higher for ammonia than for nitrogen.<br/><strong>Reason (R):</strong> Intermolecular hydrogen bonding is present in ammonia.</p>
    <div class="pq-opt pq-opt-correct">
      <div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span>Both A and R are true and R is the correct explanation of A.</span></div>
      <div class="pq-expl-label">Explanation:</div>
      <div class="pq-expl"><p>The constant 'a' measures the magnitude of attractive forces among gas molecules. These forces are greater in {tex}NH_3{/tex} due to intermolecular hydrogen bonding, so 'a' is higher for ammonia than for nitrogen.</p></div>
    </div>
    <div class="pq-opt"><span class="pq-letter">B</span><span>Both A and R are true but R is not the correct explanation of A.</span></div>
    <div class="pq-opt"><span class="pq-letter">C</span><span>A is true but R is false.</span></div>
    <div class="pq-opt"><span class="pq-letter">D</span><span>A is false but R is true.</span></div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-states-q1" onclick="pqReport(this)">Report Error</button></div>
  </div>
</div>
`;


// ── Chemical Thermodynamics ─────────────────────────────────────────────────
const CHEM_THERMODYNAMICS = PQ_PASTEL_HEAD + `
<div class="pq-wrap">
  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q1</span><span class="pq-year">2021</span></div>
    <p class="pq-question">Which one among the following is the correct relationship between {tex}C_p{/tex} and {tex}C_v{/tex} for one mole of an ideal gas?</p>
    <div class="pq-opt pq-opt-correct">
      <div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span>{tex}C_p - C_v = R{/tex}</span></div>
      <div class="pq-expl-label">Explanation:</div>
      <div class="pq-expl"><p>For one mole of an ideal gas the difference between {tex}C_p{/tex} and {tex}C_v{/tex} is constant and equals the gas constant, i.e. {tex}C_p - C_v = R{/tex}.</p></div>
    </div>
    <div class="pq-opt"><span class="pq-letter">B</span><span>{tex}C_p + C_v = R{/tex}</span></div>
    <div class="pq-opt"><span class="pq-letter">C</span><span>{tex}\\dfrac{C_p}{C_v} = R{/tex}</span></div>
    <div class="pq-opt"><span class="pq-letter">D</span><span>{tex}C_p = R\\,C_v{/tex}</span></div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-thermo-q1" onclick="pqReport(this)">Report Error</button></div>
  </div>

  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q2</span><span class="pq-year">2015</span></div>
    <p class="pq-question">The heat of combustion of carbon to {tex}CO_2{/tex} is {tex}-393.5\\ \\text{kJ/mol}{/tex}. The heat released upon the formation of 35.2 g of {tex}CO_2{/tex} from carbon and oxygen gas is</p>
    <div class="pq-opt pq-opt-correct">
      <div class="pq-correct-row"><span class="pq-letter pq-correct-letter">A</span><span>{tex}-315\\ \\text{kJ}{/tex}</span></div>
      <div class="pq-expl-label">Explanation:</div>
      <div class="pq-expl">
        <p>Moles of {tex}CO_2 = \\dfrac{35.2}{44} = 0.8\\ \\text{mol}{/tex}.</p>
        <p>Heat released {tex}= 0.8 \\times (-393.5) \\approx -315\\ \\text{kJ}{/tex}.</p>
      </div>
    </div>
    <div class="pq-opt"><span class="pq-letter">B</span><span>{tex}+315\\ \\text{kJ}{/tex}</span></div>
    <div class="pq-opt"><span class="pq-letter">C</span><span>{tex}-630\\ \\text{kJ}{/tex}</span></div>
    <div class="pq-opt"><span class="pq-letter">D</span><span>{tex}-3.15\\ \\text{kJ}{/tex}</span></div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-thermo-q2" onclick="pqReport(this)">Report Error</button></div>
  </div>

  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q3</span><span class="pq-year">2011</span></div>
    <p class="pq-question">Enthalpy change for the reaction {tex}4H(g) \\rightarrow 2H_2(g){/tex} is {tex}-869.6\\ \\text{kJ}{/tex}. The dissociation energy of the H-H bond is</p>
    <div class="pq-opt"><span class="pq-letter">A</span><span>{tex}-869.6\\ \\text{kJ}{/tex}</span></div>
    <div class="pq-opt pq-opt-correct">
      <div class="pq-correct-row"><span class="pq-letter pq-correct-letter">B</span><span>{tex}+434.8\\ \\text{kJ}{/tex}</span></div>
      <div class="pq-expl-label">Explanation:</div>
      <div class="pq-expl">
        <p>{tex}4H(g) \\rightarrow 2H_2(g);\\ \\Delta H = -869.6\\ \\text{kJ}{/tex}</p>
        <p>Reverse: {tex}2H_2(g) \\rightarrow 4H(g);\\ \\Delta H = +869.6\\ \\text{kJ}{/tex}</p>
        <p>So {tex}H_2(g) \\rightarrow 2H(g){/tex}, and the H-H bond dissociation energy {tex}= \\dfrac{869.6}{2} = 434.8\\ \\text{kJ}{/tex}.</p>
      </div>
    </div>
    <div class="pq-opt"><span class="pq-letter">C</span><span>{tex}+217.4\\ \\text{kJ}{/tex}</span></div>
    <div class="pq-opt"><span class="pq-letter">D</span><span>{tex}-434.8\\ \\text{kJ}{/tex}</span></div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-thermo-q3" onclick="pqReport(this)">Report Error</button></div>
  </div>

  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q4</span><span class="pq-year">1984</span></div>
    <p class="pq-question">The {tex}C_p - C_v{/tex} for an ideal gas is ________.</p>
    <div class="pq-solution">
      <div class="pq-solution-title">Solution</div>
      <div class="pq-solution-body">
        <p>{tex}C_p - C_v = R{/tex} (the universal gas constant) for one mole of an ideal gas.</p>
      </div>
    </div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-thermo-q4" onclick="pqReport(this)">Report Error</button></div>
  </div>
</div>
`;


// ── Hydrogen ────────────────────────────────────────────────────────────────
// NOTE: "Why does ZnO appear yellow on heating?" is a metal-oxide / defect topic.
// It is placed under 'Hydrogen' as a temporary home; move the map key below to a
// more suitable chapter (e.g. an s-block / d-block chapter) if you prefer.
const CHEM_HYDROGEN = PQ_PASTEL_HEAD + `
<div class="pq-wrap">
  <div class="pq-card">
    <div class="pq-top"><span class="pq-q">Q1</span><span class="pq-year">2019</span></div>
    <p class="pq-question">Why does ZnO appear yellow on heating?</p>
    <div class="pq-solution">
      <div class="pq-solution-title">Solution</div>
      <div class="pq-solution-body">
        <p>On heating, ZnO loses oxygen and becomes non-stoichiometric ({tex}ZnO \\rightarrow Zn_{1+x}O{/tex}).</p>
        <p>The excess {tex}Zn^{2+}{/tex} ions and the electrons trapped in the resulting vacancies (a metal-excess / F-centre type defect) absorb visible light, so the compound appears yellow when hot. On cooling, it regains oxygen and turns white again.</p>
      </div>
    </div>
    <div class="pq-foot"><button class="pq-report" data-qid="chem-hydrogen-q1" onclick="pqReport(this)">Report Error</button></div>
  </div>
</div>
`;



